import java.util.Arrays;
import java.lang.Math;

public class WeightedKNN {
 public static double weightedKNN(double[] queryPoint, double[][] trainingData, int k) {
 double[] distances = new double[trainingData.length];
 for (int i = 0; i < trainingData.length; i++) {
 distances[i] = euclideanDistance(queryPoint, trainingData[i]);
 }
 int[] kNearestNeighbors = getKNearestNeighbors(distances, k);
 double[] weights = new double[k];
 for (int i = 0; i < k; i++) {
 weights[i] = 1 / (distances[kNearestNeighbors[i]] * distances[kNearestNeighbors[i]]);
 }

 // Classification
 if (classification) {
 int[] classes = new int[k];
 for (int i = 0; i < k; i++) {
 classes[i] = (int) trainingData[kNearestNeighbors[i]][1];
 }
 int predictedClass = getPredictedClass(classes, weights);
 return predictedClass;
 } else { // Regression
 double[] values = new double[k];
 for (int i = 0; i < k; i++) {
 values[i] = trainingData[kNearestNeighbors[i]][1];
 }
 double predictedValue = getPredictedValue(values, weights);
 return predictedValue;
 }
 }
}
